local P=game:GetService("Players")local R=game:GetService("RunService")local U=game:GetService("UserInputService")local LP=P.LocalPlayer if not LP or not LP.Character then wait(1)LP=P.LocalPlayer end print("[Noclip UI] Script Loaded!")local S={NoclipEnabled=false,NoclipSpeed=50,ShowCollision=true,CollisionTransparency=0.3,KeyToggle=Enum.KeyCode.N}local NC=nil local CV={}local UI={W=false,A=false,S=false,D=false,Space=false,Ctrl=false}local G=Instance.new("ScreenGui")G.Name="NoclipUI"G.ResetOnSpawn=false G.Parent=LP:WaitForChild("PlayerGui")local MF=Instance.new("Frame")MF.Name="MainFrame"MF.Size=UDim2.new(0,350,0,450)MF.Position=UDim2.new(0,15,0,15)MF.BackgroundColor3=Color3.fromRGB(25,25,35)MF.BorderSizePixel=0 MF.Parent=G local UG=Instance.new("UIGradient")UG.Color=ColorSequence.new(Color3.fromRGB(25,25,35),Color3.fromRGB(35,35,50))UG.Rotation=90 UG.Parent=MF local TB=Instance.new("Frame")TB.Name="TitleBar"TB.Size=UDim2.new(1,0,0,50)TB.BackgroundColor3=Color3.fromRGB(15,15,25)TB.BorderSizePixel=0 TB.Parent=MF local TL=Instance.new("TextLabel")TL.Name="TitleLabel"TL.Size=UDim2.new(1,-20,1,0)TL.Position=UDim2.new(0,10,0,0)TL.BackgroundTransparency=1 TL.TextColor3=Color3.fromRGB(100,200,255)TL.Text="⚡ NOCLIP UI ⚡"TL.TextSize=20 TL.Font=Enum.Font.GothamBold TL.Parent=TB local CA=Instance.new("Frame")CA.Name="ContentArea"CA.Size=UDim2.new(1,0,1,-50)CA.Position=UDim2.new(0,0,0,50)CA.BackgroundTransparency=1 CA.Parent=MF local NL=Instance.new("TextLabel")NL.Name="NoclipLabel"NL.Size=UDim2.new(1,-20,0,30)NL.Position=UDim2.new(0,10,0,15)NL.BackgroundTransparency=1 NL.TextColor3=Color3.fromRGB(255,255,255)NL.Text="Noclip Status:"NL.TextSize=14 NL.Font=Enum.Font.Gotham NL.TextXAlignment=Enum.TextXAlignment.Left NL.Parent=CA local SI=Instance.new("TextLabel")SI.Name="StatusIndicator"SI.Size=UDim2.new(1,-20,0,30)SI.Position=UDim2.new(0,10,0,45)SI.BackgroundColor3=Color3.fromRGB(50,50,70)SI.BorderSizePixel=0 SI.TextColor3=Color3.fromRGB(255,50,50)SI.Text="❌ DISABLED"SI.TextSize=14 SI.Font=Enum.Font.GothamBold SI.Parent=CA local TB2=Instance.new("TextButton")TB2.Name="ToggleBtn"TB2.Size=UDim2.new(1,-20,0,40)TB2.Position=UDim2.new(0,10,0,85)TB2.BackgroundColor3=Color3.fromRGB(100,50,255)TB2.TextColor3=Color3.fromRGB(255,255,255)TB2.Text="ENABLE NOCLIP"TB2.TextSize=14 TB2.Font=Enum.Font.GothamBold TB2.BorderSizePixel=0 TB2.Parent=CA local SLT=Instance.new("TextLabel")SLT.Name="SpeedLabelText"SLT.Size=UDim2.new(1,-20,0,25)SLT.Position=UDim2.new(0,10,0,135)SLT.BackgroundTransparency=1 SLT.TextColor3=Color3.fromRGB(255,255,255)SLT.Text="Noclip Speed: 50"SLT.TextSize=12 SLT.Font=Enum.Font.Gotham SLT.TextXAlignment=Enum.TextXAlignment.Left SLT.Parent=CA local SS=Instance.new("TextButton")SS.Name="SpeedSlider"SS.Size=UDim2.new(1,-20,0,15)SS.Position=UDim2.new(0,10,0,165)SS.BackgroundColor3=Color3.fromRGB(50,50,70)SS.BorderSizePixel=0 SS.Text=""SS.Parent=CA local SSF=Instance.new("Frame")SSF.Name="Fill"SSF.Size=UDim2.new(0.5,0,1,0)SSF.BackgroundColor3=Color3.fromRGB(100,200,255)SSF.BorderSizePixel=0 SSF.Parent=SS local CT=Instance.new("TextButton")CT.Name="CollisionToggle"CT.Size=UDim2.new(1,-20,0,35)CT.Position=UDim2.new(0,10,0,190)CT.BackgroundColor3=Color3.fromRGB(50,150,100)CT.TextColor3=Color3.fromRGB(255,255,255)CT.Text="🔦 Show Collision: ON"CT.TextSize=12 CT.Font=Enum.Font.Gotham CT.BorderSizePixel=0 CT.Parent=CA local IB=Instance.new("TextLabel")IB.Name="InfoBox"IB.Size=UDim2.new(1,-20,0,80)IB.Position=UDim2.new(0,10,0,235)IB.BackgroundColor3=Color3.fromRGB(30,30,45)IB.BorderSizePixel=0 IB.TextColor3=Color3.fromRGB(150,200,255)IB.Text="CONTROLS\nWASD - Move\nSpace - Up\nCtrl - Down\nPress N to toggle"IB.TextSize=11 IB.Font=Enum.Font.Gotham IB.TextWrapped=true IB.Parent=CA local CB=Instance.new("TextButton")CB.Name="CloseBtn"CB.Size=UDim2.new(1,-20,0,35)CB.Position=UDim2.new(0,10,0,325)CB.BackgroundColor3=Color3.fromRGB(150,50,50)CB.TextColor3=Color3.fromRGB(255,255,255)CB.Text="DISABLE ALL"CB.TextSize=12 CB.Font=Enum.Font.GothamBold CB.BorderSizePixel=0 CB.Parent=CA local SL=Instance.new("TextLabel")SL.Name="StatsLabel"SL.Size=UDim2.new(1,-20,0,60)SL.Position=UDim2.new(0,10,0,370)SL.BackgroundColor3=Color3.fromRGB(30,30,45)SL.BorderSizePixel=0 SL.TextColor3=Color3.fromRGB(100,255,100)SL.Text="Position: 0, 0, 0\nSpeed: 0 studs/s"SL.TextSize=10 SL.Font=Enum.Font.Gotham SL.TextXAlignment=Enum.TextXAlignment.Left SL.TextYAlignment=Enum.TextYAlignment.Top SL.Parent=CA local function EnableNoclip()if NC then NC:Disconnect()end local C=LP.Character if not C then return end local H=C:FindFirstChild("HumanoidRootPart")if not H then return end NC=R.Heartbeat:Connect(function()if not S.NoclipEnabled then return end C=LP.Character if not C then return end for _,Part in pairs(C:GetDescendants())do if Part:IsA("BasePart")then Part.CanCollide=false end end end)print("[Noclip UI] Noclip enabled!")end local function DisableNoclip()if NC then NC:Disconnect()NC=nil end local C=LP.Character if C then for _,Part in pairs(C:GetDescendants())do if Part:IsA("BasePart")then Part.CanCollide=true end end end print("[Noclip UI] Noclip disabled!")end TB2.MouseButton1Click:Connect(function()S.NoclipEnabled=not S.NoclipEnabled if S.NoclipEnabled then EnableNoclip()TB2.Text="DISABLE NOCLIP"TB2.BackgroundColor3=Color3.fromRGB(255,100,50)SI.TextColor3=Color3.fromRGB(50,255,100)SI.Text="✅ ENABLED"else DisableNoclip()TB2.Text="ENABLE NOCLIP"TB2.BackgroundColor3=Color3.fromRGB(100,50,255)SI.TextColor3=Color3.fromRGB(255,50,50)SI.Text="❌ DISABLED"end end)CT.MouseButton1Click:Connect(function()S.ShowCollision=not S.ShowCollision CT.Text=S.ShowCollision and"🔦 Show Collision: ON"or"🔦 Show Collision: OFF"CT.BackgroundColor3=S.ShowCollision and Color3.fromRGB(50,150,100)or Color3.fromRGB(100,100,100)end)CB.MouseButton1Click:Connect(function()if S.NoclipEnabled then S.NoclipEnabled=false DisableNoclip()TB2.Text="ENABLE NOCLIP"TB2.BackgroundColor3=Color3.fromRGB(100,50,255)SI.TextColor3=Color3.fromRGB(255,50,50)SI.Text="❌ DISABLED"end print("[Noclip UI] All features disabled!")end)local speedDragging=false SS.MouseButton1Down:Connect(function()speedDragging=true end)U.InputEnded:Connect(function(input,gameProcessed)if input.UserInputType==Enum.UserInputType.MouseButton1 then speedDragging=false end end)R.RenderStepped:Connect(function()if speedDragging then local mouse=LP:GetMouse()local sliderPos=SS.AbsolutePosition.X local sliderSize=SS.AbsoluteSize.X local mouseX=mouse.X local percentage=math.clamp((mouseX-sliderPos)/sliderSize,0,1)local newSpeed=math.floor(percentage*250+10)S.NoclipSpeed=newSpeed SLT.Text="Noclip Speed: "..newSpeed SSF.Size=UDim2.new(percentage,0,1,0)end if S.NoclipEnabled then local C=LP.Character if C then local H=C:FindFirstChild("HumanoidRootPart")if H then local pos=H.Position local vel=H.AssemblyLinearVelocity.Magnitude SL.Text=string.format("Pos: %.0f, %.0f, %.0f\nSpeed: %.0f studs/s",pos.X,pos.Y,pos.Z,vel)end end end end)U.InputBegan:Connect(function(input,gameProcessed)if gameProcessed then return end if input.KeyCode==S.KeyToggle then TB2:MouseButton1Click()end
